import React, { useState, useEffect } from 'react';
import { Shield, User, Stethoscope, Eye, EyeOff, ArrowRight, Mail, Lock, CheckCircle, AlertCircle, Zap, HeartPulse } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { API_BASE_URL } from '../config';

const Login = () => {
  const navigate = useNavigate();
  const [selectedRole, setSelectedRole] = useState('patient');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(null);
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [mounted, setMounted] = useState(false);

  const roles = [
    { id: 'admin', label: 'Admin', icon: Shield, color: 'from-blue-600 to-indigo-600', bg: 'bg-gradient-to-r from-blue-500/10 to-indigo-500/10' },
    { id: 'patient', label: 'Patient', icon: User, color: 'from-emerald-600 to-teal-600', bg: 'bg-gradient-to-r from-emerald-500/10 to-teal-500/10' },
    { id: 'doctor', label: 'Doctor', icon: Stethoscope, color: 'from-purple-600 to-pink-600', bg: 'bg-gradient-to-r from-purple-500/10 to-pink-500/10' },
  ];

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      // Simulate network delay
      await new Promise(resolve => setTimeout(resolve, 1200));

      const response = await fetch(`${API_BASE_URL}/api/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, role: selectedRole }),
      });

      if (response.ok) {
        const data = await response.json();
        localStorage.setItem('token', data.token);
        localStorage.setItem('userRole', data.role);
        localStorage.setItem('userEmail', email);

        // Success animation then redirect
        setTimeout(() => {
          if (data.role === 'admin') navigate('/admin');
          else if (data.role === 'doctor') navigate('/doctor');
          else navigate('/patient');
        }, 800);
      } else {
        const errorData = await response.json();
        setError(errorData.error || 'Login failed');
      }
    } catch (error) {
      setError('Network error. Please check your connection.');
    } finally {
      setIsLoading(false);
    }
  };

  if (!mounted) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50/50 to-indigo-100 relative overflow-hidden">
      {/* Animated Background Elements */}
      <div className="absolute inset-0">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-gradient-to-r from-blue-400/20 to-purple-400/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute -bottom-40 -left-40 w-96 h-96 bg-gradient-to-r from-emerald-400/20 to-teal-400/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-gradient-to-r from-purple-400/10 to-pink-400/10 rounded-full blur-2xl animate-pulse"></div>
      </div>

      <div className="relative z-10 flex items-center justify-center min-h-screen px-4 py-12 lg:px-8">
        <div className="w-full max-w-4xl flex flex-col lg:flex-row gap-12 lg:gap-20 items-center justify-center">

          {/* Left Side - Illustration & Features */}
          <div className="w-full lg:w-1/2 max-w-md text-center lg:text-left animate-fade-in-up">
            <div className="relative">
              <div className="relative z-10 mx-auto lg:ml-0 w-80 h-80 lg:w-96 lg:h-96 bg-gradient-to-br from-blue-500/20 via-purple-500/20 to-emerald-500/20 rounded-3xl backdrop-blur-xl border border-white/30 shadow-2xl p-12 flex items-center justify-center">
                <div className="relative">
                  <HeartPulse className="w-32 h-32 text-white/80 animate-pulse mx-auto" />
                  <div className="absolute -top-4 -right-4 w-24 h-24 bg-gradient-to-r from-emerald-400 to-teal-500 rounded-2xl shadow-xl animate-bounce"></div>
                  <div className="absolute -bottom-6 -left-6 w-20 h-20 bg-gradient-to-r from-purple-400 to-pink-500 rounded-2xl shadow-xl animate-bounce delay-500"></div>
                </div>
              </div>
            </div>

            <div className="mt-12 space-y-6">
              <h1 className="text-4xl lg:text-5xl font-black bg-gradient-to-r from-gray-900 via-blue-900 to-purple-900 bg-clip-text text-transparent leading-tight">
                Welcome to 
                <span className="block bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent">
                  MedCare Pro
                </span>
              </h1>
              <div className="space-y-4">
                <div className="flex items-center gap-3 p-4 bg-white/60 backdrop-blur-sm rounded-2xl shadow-lg border border-white/50">
                  <div className="w-12 h-12 bg-gradient-to-r from-emerald-500 to-teal-600 rounded-xl flex items-center justify-center shadow-lg">
                    <Zap className="w-6 h-6 text-white" />
                  </div>
                  <div>
                    <h3 className="font-bold text-xl text-gray-900">Lightning Fast</h3>
                    <p className="text-gray-600">Access your records instantly</p>
                  </div>
                </div>
                <div className="flex items-center gap-3 p-4 bg-white/60 backdrop-blur-sm rounded-2xl shadow-lg border border-white/50">
                  <div className="w-12 h-12 bg-gradient-to-r from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg">
                    <Shield className="w-6 h-6 text-white" />
                  </div>
                  <div>
                    <h3 className="font-bold text-xl text-gray-900">HIPAA Secure</h3>
                    <p className="text-gray-600">Enterprise-grade encryption</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Right Side - Login Form */}
          <div className="w-full lg:w-1/2 max-w-md">
            <div className="bg-white/90 backdrop-blur-xl rounded-3xl shadow-2xl border border-white/50 p-10 relative overflow-hidden group">
              {/* Decorative elements */}
              <div className="absolute inset-0 bg-gradient-to-br from-blue-500/5 via-purple-500/5 to-emerald-500/5"></div>
              <div className="absolute top-0 left-0 w-48 h-48 bg-gradient-to-r from-blue-400/20 to-purple-400/20 rounded-full -translate-x-24 translate-y-24 blur-xl"></div>
              <div className="absolute bottom-0 right-0 w-40 h-40 bg-gradient-to-r from-emerald-400/20 to-teal-400/20 rounded-full translate-x-16 -translate-y-16 blur-xl"></div>

              <div className="relative z-10">
                <div className="text-center mb-2">
                  <div className="inline-flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-100 to-indigo-100 text-blue-800 rounded-2xl font-semibold shadow-lg mb-8">
                    <Shield className="w-5 h-5" />
                    <span>Secure Login Portal</span>
                  </div>
                </div>

                <h2 className="text-4xl font-black bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent text-center mb-2">
                  Sign In
                </h2>
                <p className="text-xl text-gray-600 text-center mb-10 font-medium">Access your medical portal securely</p>

                {/* Role Selection */}
                <div className="mb-8">
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {roles.map((role) => (
                      <div
                        key={role.id}
                        className={`group relative p-6 rounded-2xl border-2 transition-all duration-500 cursor-pointer hover:shadow-xl hover:-translate-y-1 hover:scale-[1.02] ${
                          selectedRole === role.id
                            ? `border-white/50 ${role.bg} shadow-2xl shadow-${role.color.replace('from-', '').replace('to-', '')}/25 scale-105`
                            : 'border-gray-200 hover:border-gray-300 bg-white/50'
                        }`}
                        onClick={() => setSelectedRole(role.id)}
                      >
                        <div className="absolute inset-0 bg-gradient-to-r from-white/0 to-white/20 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                        <div className="relative z-10 flex flex-col items-center space-y-3">
                          <div className={`w-16 h-16 ${role.color} rounded-2xl flex items-center justify-center shadow-xl group-hover:scale-110 transition-all duration-300`}>
                            <role.icon className="w-8 h-8 text-white" />
                          </div>
                          <h4 className="font-bold text-xl bg-gradient-to-r from-gray-900 to-gray-700 bg-clip-text text-transparent">
                            {role.label}
                          </h4>
                          {selectedRole === role.id && (
                            <CheckCircle className="w-6 h-6 text-emerald-500 animate-bounce" />
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                  {/* Email Input */}
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none z-10">
                      <Mail className="h-5 w-5 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
                    </div>
                    <input
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      placeholder="Enter your email"
                      className="w-full pl-12 pr-4 py-5 bg-white/50 backdrop-blur-sm border-2 border-gray-200 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 text-lg placeholder-gray-400 peer hover:border-gray-300"
                      required
                      disabled={isLoading}
                    />
                    {email && (
                      <CheckCircle className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-emerald-500 opacity-0 peer-valid:opacity-100 transition-opacity" />
                    )}
                  </div>

                  {/* Password Input */}
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none z-10">
                      <Lock className="h-5 w-5 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
                    </div>
                    <input
                      type={showPassword ? "text" : "password"}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter your password"
                      className="w-full pl-12 pr-12 py-5 bg-white/50 backdrop-blur-sm border-2 border-gray-200 rounded-2xl shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 text-lg placeholder-gray-400 peer hover:border-gray-300"
                      required
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      className="absolute inset-y-0 right-0 pr-4 flex items-center transition-all duration-300 hover:scale-110"
                      onClick={() => setShowPassword(!showPassword)}
                      disabled={isLoading}
                    >
                      {showPassword ? (
                        <EyeOff className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                      ) : (
                        <Eye className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                      )}
                    </button>
                  </div>

                  {/* Error Message */}
                  {error && (
                    <div className="p-4 bg-gradient-to-r from-red-500/10 to-rose-500/10 border border-red-200 rounded-2xl backdrop-blur-sm animate-shake">
                      <div className="flex items-center gap-3">
                        <AlertCircle className="w-6 h-6 text-red-500 flex-shrink-0" />
                        <p className="text-red-800 font-medium">{error}</p>
                      </div>
                    </div>
                  )}

                  {/* Submit Button */}
                  <button
                    type="submit"
                    disabled={isLoading || !email || !password}
                    className={`group w-full relative overflow-hidden py-5 px-8 rounded-2xl font-bold text-lg transition-all duration-500 transform flex items-center justify-center gap-3 shadow-xl ${
                      isLoading || !email || !password
                        ? 'bg-gray-400 cursor-not-allowed shadow-none'
                        : 'bg-gradient-to-r from-blue-600 to-indigo-700 hover:from-blue-700 hover:to-indigo-800 shadow-blue-500/25 hover:shadow-2xl hover:-translate-y-1 active:scale-95'
                    } text-white`}
                  >
                    {isLoading ? (
                      <>
                        <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white"></div>
                        Signing In...
                      </>
                    ) : (
                      <>
                        Login as{' '}
                        <span className="font-black bg-gradient-to-r from-white/80 to-white bg-clip-text text-transparent drop-shadow-lg">
                          {roles.find(r => r.id === selectedRole)?.label}
                        </span>
                        <ArrowRight className="w-5 h-5 group-hover:translate-x-2 transition-transform" />
                      </>
                    )}
                  </button>
                </form>

                {/* Divider */}
                <div className="relative my-10">
                  <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-gray-200"></div>
                  </div>
                  <div className="relative flex justify-center text-xs uppercase">
                    <span className="px-4 bg-white/90 backdrop-blur-sm text-gray-500 font-semibold">or</span>
                  </div>
                </div>

                {/* Alternative Actions */}
                <div className="grid grid-cols-2 gap-4">
                  <button
                    type="button"
                    onClick={() => navigate('/forgot-password')}
                    className="group p-4 bg-gradient-to-r from-gray-50 to-gray-100 hover:from-gray-100 hover:to-gray-200 rounded-2xl border border-gray-200 hover:shadow-md transition-all duration-300 hover:scale-105 flex flex-col items-center gap-2 text-sm font-semibold text-gray-700"
                    disabled={isLoading}
                  >
                    <Lock className="w-6 h-6 group-hover:scale-110 transition-transform" />
                    Forgot Password?
                  </button>
                  <button
                    type="button"
                    onClick={() => navigate('/signup')}
                    className="group p-4 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 flex flex-col items-center gap-2 text-white font-semibold shadow-emerald-500/25"
                    disabled={isLoading}
                  >
                    <UserPlus className="w-6 h-6 group-hover:scale-110 transition-transform" />
                    Create Account
                  </button>
                </div>
              </div>
            </div>

            {/* Bottom Trust Indicators */}
            <div className="mt-10 text-center space-y-4">
              <div className="flex items-center justify-center gap-8 text-sm text-gray-500">
                <div className="flex items-center gap-2">
                  <CheckCircle className="w-5 h-5 text-emerald-500" />
                  <span>HIPAA Compliant</span>
                </div>
                <div className="flex items-center gap-2">
                  <CheckCircle className="w-5 h-5 text-emerald-500" />
                  <span>24/7 Support</span>
                </div>
                <div className="flex items-center gap-2">
                  <CheckCircle className="w-5 h-5 text-emerald-500" />
                  <span>Encrypted</span>
                </div>
              </div>
              <p className="text-xs text-gray-400">
                © 2024 MedCare Pro. All rights reserved.
              </p>
            </div>
          </div>
        </div>
      </div>

      <style jsx>{`
        @keyframes fade-in-up {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px);
                    50% { transform: translateX(4px); }
          75% { transform: translateX(-2px); }
        }
        .animate-fade-in-up {
          animation: fade-in-up 0.8s ease-out;
        }
        .animate-shake {
          animation: shake 0.5s ease-in-out;
        }
        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-10px); }
        }
        .animate-float {
          animation: float 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default Login;
